"""
mkt-original commentary -- Jeremiah chapters 31-32
Run: python3 scripts/zc-original-jeremiah-31-32.py

Ch31: The great restoration oracle — return from exile, Rachel's weeping, Ephraim's
  repentance, the new covenant (bĕrît ḥădāšâ — the only OT occurrence of the exact phrase),
  cosmic guarantees, and the rebuilt city.
Ch32: The field purchase at Anathoth — gĕʾullâ (kinsman-redeemer right), prophetic symbolic
  act of hope amid siege, Jeremiah's prayer, YHWH's answer, and the everlasting covenant
  (bĕrît ʿôlām) with blessings from all heart and soul.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / f"mkt-{layer}" / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / f"mkt-{layer}" / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    # Never overwrite existing entries — safe to re-run
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JEREMIAH = {
  "31": {
    "1": "<p><strong>Bāʿēt hahîʾ</strong> (<em>bāʿēt hahîʾ</em>), \"at that time,\" opens ch31 as a direct continuation of the promise begun in ch30. The phrase functions as a temporal bracket connecting the new covenant oracle to the preceding reversal of fortunes. YHWH declares himself <strong>lēʾlōhîm</strong> (<em>lēʾlōhîm</em>) — God — to <em>kol mišpĕḥôt yiśrāʾēl</em>, all the families/clans of Israel, not just Judah. The breadth is programmatic: the restoration encompasses the whole covenant people, including the northern kingdom carried away by Assyria.</p>",
    "2": "<p><strong>Māṣāʾ ḥēn bammidbar</strong> (<em>māṣāʾ ḥēn bammidbar</em>): the exodus wilderness becomes the paradigm for divine grace in judgment. The survivors of the sword (<em>śĕrîdê ḥāreḇ</em>) find grace (<em>ḥēn</em>) not as earned status but as unexpected gift. <strong>Hālôk lĕhargîʿô</strong> (<em>hālôk lĕhargîʿô</em>), \"going to give him rest,\" uses the Hiphil of <em>rāgaʿ</em> (to give rest, to quiet). The wilderness, normally a place of death and testing, becomes the space of grace — a Hosea 2 pattern (\"I will allure her into the wilderness and speak tenderly\").</p>",
    "3": "<p>The pivotal theological statement: <strong>ʾahăḇat ʿôlām ʾăhăḇtîḵ</strong> (<em>ʾahăḇat ʿôlām ʾăhăḇtîḵ</em>) — \"with an everlasting love I have loved you.\" The noun <em>ʿôlām</em> (long duration, eternity) modifies the love-action absolutely: this is no conditional or seasonal affection but the settled disposition of YHWH toward Israel from of old (<em>mērāḥôq</em>, \"from far away/long ago\"). <strong>Mĕšaḵtîḵ ḥāsed</strong> (<em>mĕšaḵtîḵ ḥāsed</em>): \"I have drawn you with steadfast love/ḥesed.\" The verb <em>māšaḵ</em> (to draw, pull) combined with <em>ḥesed</em> is unusual — YHWH's covenant loyalty is portrayed as the cord by which he draws the exiled people back. John 6:44 (\"no one can come to me unless the Father who sent me draws him\") uses <em>helkō</em> in a directly analogous theological move.</p>",
    "4": "<p><strong>Tîḇnēḵ wĕniḇnêt</strong> (<em>tîḇnēḵ wĕniḇnêt</em>): \"I will build you up and you will be built\" — the Qal imperfect with the Niphal passive creates a divine-human synergy: YHWH's action produces the community's rebuilt state. <strong>Bĕtûlat yiśrāʾēl</strong> (<em>bĕtûlat yiśrāʾēl</em>), \"virgin Israel,\" is not a critique of moral status but a term of tender address recalling the nation before the violations of exile. The image of women taking up tambourines (<em>tuppîm</em>) to join the dance (<em>mĕḥôl hāmĕśaḥăqîm</em>) echoes Miriam's victory celebration (Exod 15:20), placing restoration in the typological pattern of exodus-deliverance.</p>",
    "5": "<p><strong>Nāṭĕʿû kĕrāmîm bĕhārê šōmĕrôn</strong> (<em>nāṭĕʿû kĕrāmîm bĕhārê šōmĕrôn</em>): vineyards replanted on the hills of Samaria signals the inclusion of the northern kingdom (Ephraim/Israel) in the restoration — not merely Judah. <strong>Nāṭĕʿû ḥillĕlû</strong> (<em>nāṭĕʿû ḥillĕlû</em>): \"those who plant will also enjoy/use\" (Piel of <em>ḥālal</em>, to begin as common/unconsecrated after the three-year waiting period, Lev 19:23-25). The allusion to the firstfruits law implies a stable, normalized covenant life has returned — planting carries through to harvest without the interruption of war or exile.</p>",
    "6": "<p><strong>Nōṣĕrîm bĕhar ʾEprayim</strong> (<em>nōṣĕrîm bĕhar ʾEprayim</em>): \"watchmen on the hills of Ephraim\" — the term <em>nōṣĕr</em> (Qal participle of <em>nāṣar</em>, to watch) normally refers to military sentinels or lookouts over vineyards. Here they call pilgrims to worship rather than warning of danger. <strong>Qûmû wĕnaʿăleh ṣiyyôn</strong> (<em>qûmû wĕnaʿăleh ṣiyyôn</em>): the pilgrimage call \"Rise up! Let us go up to Zion\" is the <em>ʿaliyyâ</em> vocabulary of the Psalms of Ascent (Ps 120-134). The convergence of Ephraim and Judah in a single pilgrimage to Zion marks the healing of the north-south schism that began with Rehoboam.</p>",
    "7": "<p><strong>Ronnû lĕyaʿăqōḇ śimḥâ</strong> (<em>ronnû lĕyaʿăqōḇ śimḥâ</em>): \"Shout with joy for Jacob\" — <em>rānan</em> is the exultant, ringing cry of joy that belongs to the Psalter's celebration vocabulary. <strong>Ṣahlû bĕrōʾš haggôyim</strong> (<em>ṣahlû bĕrōʾš haggôyim</em>): \"shout at the head of the nations\" — the restored Israel does not hide its praise; the proclamation is public, international witness. <strong>Hôšaʿ YHWH ʾet-ʿammeḵā ʾet šĕʾērît yiśrāʾēl</strong> (<em>hôšaʿ YHWH ʾet-ʿammeḵā</em>): the imperative to save echoes the <em>hôšîʿāh nāʾ</em> of Ps 118:25 — the same liturgical cry that greets Jesus at the triumphal entry (\"Hosanna,\" Matt 21:9).</p>",
    "8": "<p><strong>Hinnĕnî mēbîʾ ôtām mēʾereṣ ṣāpôn</strong> (<em>hinnĕnî mēbîʾ ôtām</em>): the emphatic <em>hinnēnî</em> (\"behold me\") announces YHWH's direct personal action in the return. The gathering (<em>qibbēṣ</em>) is universal: <strong>ʾiwwēr wĕpissēaḥ hārâ wĕyōlĕdet yaḥdāw</strong> (<em>ʾiwwēr wĕpissēaḥ hārâ wĕyōlĕdet</em>) — blind, lame, pregnant, and laboring women. These are precisely those who by human capacity are least able to make a desert march. Their inclusion reverses the values of the ban on entering the sanctuary (Lev 21:18; 2 Sam 5:8) — in YHWH's restoration, the excluded are specifically gathered. <strong>Qāhāl gādôl</strong> (<em>qāhāl gādôl</em>), \"a great assembly,\" is the term for the covenant assembly of Israel.</p>",
    "9": "<p><strong>Biḇkî yāḇōʾû ûḇĕtaḥănûnîm ʾôḇîlēm</strong> (<em>biḇkî yāḇōʾû</em>): they come with weeping — not weeping of despair but of repentance and profound relief, as the Hiphil <em>ʾôḇîlēm</em> (\"I will lead them\") makes clear: YHWH himself leads the procession. <strong>ʾEl naḥălê māyim bĕdereḵ yāšār lōʾ yikkāšlû bāh</strong> (<em>ʾel naḥălê māyim</em>): streams of water on a level path — the exodus/wilderness imagery inverted; instead of waterlessness and stumbling, YHWH provides both the path and the sustaining water. The climax: <strong>kî-hāyîtî lĕyiśrāʾēl lĕʾāḇ ûʾEprayim bĕḵôrî hûʾ</strong> (<em>kî-hāyîtî lĕyiśrāʾēl lĕʾāḇ</em>) — \"For I have become a father to Israel, and Ephraim is my firstborn.\" The designation <em>bĕḵôr</em> (firstborn) for Ephraim over Manasseh recalls Jacob's reversal (Gen 48:19); more fundamentally, it echoes Exod 4:22 (\"Israel is my firstborn son\") and grounds the paternal claim of YHWH as the basis for filial restoration.</p>",
    "10": "<p><strong>Šimʿû dĕḇar-YHWH gôyim</strong> (<em>šimʿû dĕḇar-YHWH gôyim</em>): the proclamation extends to the nations — the restoration of Israel is a matter of international witness. <strong>Mĕzārēh yiśrāʾēl yĕqabbĕṣennû ûšĕmārô kĕrōʿeh ʿedrô</strong> (<em>mĕzārēh yiśrāʾēl yĕqabbĕṣennû</em>): \"He who scattered Israel will gather him, and he will watch over him as a shepherd watches his flock.\" The same agent who scattered now gathers — the scattering was punitive, the gathering is redemptive, but the shepherd (<em>rōʿeh</em>) image is the same continuous care. Jesus's self-identification as the good shepherd (John 10:11) and his mission to gather the scattered sheep of the house of Israel (Matt 15:24) are direct fulfillments of this restoration-shepherd expectation.</p>",
    "11": "<p><strong>Kî-pādâ YHWH ʾet-yaʿăqōḇ wĕgĕʾālô miyyad ḥāzāq mimmennû</strong> (<em>kî-pādâ YHWH ʾet-yaʿăqōḇ wĕgĕʾālô</em>): two key redemption terms in parallel: <em>pādâ</em> (ransom, to pay the price of liberation — a commercial/legal term) and <em>gāʾal</em> (kinsman-redeemer act, to act as family-protector who retrieves what was lost). YHWH acts as both ransomer and kinsman-redeemer. <strong>Miyyad ḥāzāq mimmennû</strong> (<em>miyyad ḥāzāq mimmennû</em>): \"from the hand of one too strong for him\" — Jacob/Israel could not free himself from Babylon's grip; the deliverance is entirely YHWH's initiative and power. Paul uses <em>pādâ</em>/<em>apolytrōsis</em> and <em>gāʾal</em>/<em>exagorazō</em> vocabulary directly for Christ's redemptive work (Rom 3:24; Gal 3:13).</p>",
    "12": "<p><strong>Wĕbāʾû wĕrinnĕnû biḇmôt ṣiyyôn</strong> (<em>wĕbāʾû wĕrinnĕnû biḇmôt ṣiyyôn</em>): the pilgrimage song reaches its destination — Zion's heights. <strong>Wĕnāhărû ʾel-ṭûḇ YHWH</strong> (<em>wĕnāhărû ʾel-ṭûḇ YHWH</em>): the unusual verb <em>nāhar</em> (to flow, to stream — normally of rivers flowing toward the sea) pictures the people streaming toward YHWH's goodness as rivers flow; a radiant face (<em>nāhar</em> also means to shine/be radiant, Isa 60:5) captures the dual meaning. <strong>Wĕhāytâ napšām kĕgan rāweh</strong> (<em>kĕgan rāweh</em>): \"their being will be like a well-watered garden\" — the nephesh as the whole person, fully satisfied; Ps 23:1-3 uses the same imagery of YHWH as the shepherd who leads beside still waters and restores the nephesh.</p>",
    "13": "<p><strong>Ûḇĕtûlâ tiśmaḥ bĕmāḥôl ûḇaḥûrîm ûzĕqēnîm yaḥdāw</strong> (<em>ûḇĕtûlâ tiśmaḥ bĕmāḥôl</em>): the communal celebration encompasses all generations — young women, young men, and elders rejoice together. <strong>Wĕhāpaḵtî ʾeḇlām lĕśāśôn</strong> (<em>wĕhāpaḵtî ʾeḇlām lĕśāśôn</em>): \"I will turn their mourning into joy\" — the Qal perfect of <em>hāpaḵ</em> (to overturn, reverse) is the same verb used for Sodom's overthrow (Gen 19:25); here divine reversal works positively. The consolation (<em>niḥamtîm</em>) and rejoicing in place of sorrow (<em>śamaḥtîm miyyĕgônām</em>) becomes the NT pattern of divine comfort throughout (2 Cor 1:3-4; Rev 21:4).</p>",
    "14": "<p><strong>Wĕribbêtî nefesh hakkōhănîm dāšen</strong> (<em>wĕribbêtî nefesh hakkōhănîm dāšen</em>): the priests are filled with fatness (<em>dāšen</em> — rich abundance, the fat of offerings representing fullness of blessing). The priestly abundance is YHWH's own initiative (<em>wĕribbêtî</em>, I will satisfy them abundantly). <strong>Wĕʾammî ʾet-ṭûḇî yiśbāʿû</strong> (<em>wĕʾammî ʾet-ṭûḇî yiśbāʿû</em>): \"my people will be satisfied with my goodness\" — <em>ṭôḇ</em> (goodness) is the same word used in v12 (\"flowing toward the goodness of YHWH\"). The repetition creates an inclusion framing vv10-14 as a single portrait of covenantal abundance.</p>",
    "15": "<p>The most cited verse of this chapter outside the New Covenant oracle itself: <strong>qôl bĕrāmâ nišmaʿ nehi bĕḵî tamrûrîm Rāḥēl mĕḇakkâ ʿal-bānêhā</strong> (<em>qôl bĕrāmâ nišmaʿ nehi</em>). <em>Rāmâ</em> was near Bethlehem in Benjamin's territory, also the site where exiles were assembled before deportation (Jer 40:1). Rachel, the mother of Benjamin and Joseph (through whom came Ephraim and Manasseh) — the matriarch of the northern tribes — weeps for children who \"are no more\" (<em>ʾênennû</em>, a permanent-state negation). <strong>Mēʾănâ lĕhinnāḥēm</strong> (<em>mēʾănâ lĕhinnāḥēm</em>): she refuses comfort, because comfort would require acknowledging the reality of the loss as final. Matthew 2:18 cites this text for Herod's slaughter of the innocents, reading Rachel's weeping as a typological pattern: the same grief that accompanied Israel's exile accompanies the persecution of the Messiah in his infancy.</p>",
    "16": "<p><strong>Minĕʿî qôlēḵ mibbekî wĕʿênayiḵ middimʿâ</strong> (<em>minĕʿî qôlēḵ mibbekî</em>): YHWH's response to Rachel's weeping is a command to stop — not because the grief is unjustified, but because it is now unnecessary. <strong>Yēš śākār lĭpĕʿullātēḵ</strong> (<em>yēš śākār lĭpĕʿullātēḵ</em>): \"there is a reward/wages for your labor\" — the labor (<em>pĕʿullâ</em>) of bearing and raising children has not been in vain; those children will return. <strong>Wĕšāḇû mēʾereṣ ʾôyēḇ</strong> (<em>wĕšāḇû mēʾereṣ ʾôyēḇ</em>): the return from the land of the enemy is the reversal that transforms the weeping into hope.</p>",
    "17": "<p><strong>Wĕyēš-tiqwâ lĕʾaḥărîtēḵ</strong> (<em>wĕyēš-tiqwâ lĕʾaḥărîtēḵ</em>): \"there is hope for your future\" — the term <em>ʾaḥărît</em> (latter end, future) in the context of hope is a key restoration term in Jeremiah (29:11: \"plans for a future and a hope\"). The hope is not abstract optimism but grounded in YHWH's specific promise: <em>wĕšāḇû ḇānîm ligĕḇûlām</em>, \"your children will return to their own territory.\" The land promise is inseparable from the restoration hope — it is a return to the concrete inheritance.</p>",
    "18": "<p>The lament of Ephraim (the northern kingdom as a whole): <strong>šāmôaʿ šāmaʿtî ʾEprayim mitnôdēd</strong> (<em>šāmôaʿ šāmaʿtî ʾEprayim mitnôdēd</em>): the doubled infinitive absolute <em>šāmôaʿ šāmaʿtî</em> emphasizes YHWH's attentive hearing. <strong>Yissartanî wāʾiwwāsēr kĕʿēgel lōʾ lummad</strong> (<em>yissartanî wāʾiwwāsēr kĕʿēgel lōʾ lummad</em>): \"You disciplined me, and I received the discipline, like an untrained calf\" — the calf metaphor for an undisciplined, stubborn people (Hos 4:16: \"Israel is stubborn like a stubborn heifer\"); Ephraim confesses that the exile was just discipline, not capricious cruelty. <strong>hăšîḇênî wĕʾāšûḇâ</strong> (<em>hăšîḇênî wĕʾāšûḇâ</em>): \"Restore me and I will be restored\" — the classic <em>šûḇ</em> vocabulary, but with a theologically important structure: the repentance/return can only happen if YHWH himself initiates it. Cf. Lam 5:21 (\"Return us to yourself, O LORD, that we may return\"). This is the OT expression of the Augustinian/Reformed insight that even repentance is a divine gift.</p>",
    "19": "<p><strong>Kî ʾaḥărê šûḇî niḥamtî</strong> (<em>kî ʾaḥărê šûḇî niḥamtî</em>): \"After I turned away I repented/was comforted\" — <em>niḥam</em> (Niphal of <em>nāḥam</em>) can mean either to repent or to be comforted; here it is genuine remorse. <strong>Wĕʾaḥărê higgāḏĕʿî sāpaḵtî ʿal-yārēḵ</strong> (<em>wĕʾaḥărê higgāḏĕʿî sāpaḵtî ʿal-yārēḵ</em>): \"after I understood, I struck my thigh in shame\" — striking the thigh is a gesture of deep grief and horror at one's own behavior (Ezek 21:12). <strong>Bōštî wĕgam niklāmtî kî nāśāʾtî ḥerpat nĕʿûrāy</strong> (<em>bōštî wĕgam niklāmtî</em>): the shame vocabulary is twofold — <em>bōšet</em> (the internal state of shame) and <em>kĕlimmâ</em> (public disgrace/humiliation). The exile has exposed the failure of the nation's entire early history.</p>",
    "20": "<p>The most tender verse in Jeremiah — YHWH's internal monologue over wayward Ephraim: <strong>hăḇēn yaqîr lî ʾEprayim</strong> (<em>hăḇēn yaqîr lî ʾEprayim</em>): \"Is Ephraim not my dear/precious son?\" — <em>yāqîr</em> (Piel participle of <em>yāqar</em>, to be precious/honored) — the question expects \"yes.\" <strong>ʾim yeled šaʿăšûʿîm</strong> (<em>ʾim yeled šaʿăšûʿîm</em>): \"is he not my darling child?\" — <em>šaʿăšûʿ</em> (child of delight, darling) appears in Prov 8:30-31 for Wisdom as YHWH's delight. <strong>midday dabberî bô zākōr ʾezkĕrennû ʿôd</strong> (<em>midday dabberî bô zākōr ʾezkĕrennû</em>): \"Even when I speak against him I still remember him\" — the remembering (<em>zākar</em>) is covenant memory, the same <em>zākar</em> that YHWH exercises in Exod 2:24 of his covenant with Abraham. <strong>ʿal-kēn hāmû mēʿay lô raḥēm ʾăraḥămennû</strong> (<em>ʿal-kēn hāmû mēʿay lô raḥēm ʾăraḥămennû</em>): \"therefore my heart is deeply moved for him; I will surely have compassion on him\" — <em>hāmâ mēʿayim</em> is lit. \"my bowels/intestines roar/churn\" — the most visceral expression of emotion in Hebrew, used also in 1 Kings 3:26 for the real mother's compassion for her child. <em>raḥēm ʾăraḥămennû</em>: doubled infinitive absolute for absolute certainty: \"I will most certainly have compassion.\" The root <em>riḥam</em> is cognate with <em>reḥem</em> (womb) — this is the maternal compassion YHWH uses for himself in Isa 49:15 (\"Can a mother forget her nursing child... even if she should forget, I will not forget you\").</p>",
    "21": "<p><strong>Haṣṣiḇî lāḵ ṣiyyunîm śîmî lāḵ tamrurîm</strong> (<em>haṣṣiḇî lāḵ ṣiyyunîm</em>): \"Set up road markers for yourself, establish guideposts\" — the feminine singular imperatives address virgin Israel. <em>Ṣiyyûn</em> (marker, signpost) and <em>tamrûr</em> (bitter marker, boundary post) are both terms for landmarks along a road; in the context of exile this means remembering the way home so the return route is known. <strong>Šîtî libbēḵ lammĕsillâ</strong> (<em>šîtî libbēḵ lammĕsillâ</em>): \"set your heart on the highway\" — the <em>mĕsillâ</em> is the raised causeway/highway, the main road. Memory of the way home and intentional heart-orientation toward return are the twin responsibilities of the exile.</p>",
    "22": "<p>The most debated verse in the chapter: <strong>kî-bārāʾ YHWH ḥădāšâ bāʾāreṣ nĕqēḇâ tĕsôḇēḇ gāḇer</strong> (<em>kî-bārāʾ YHWH ḥădāšâ bāʾāreṣ nĕqēḇâ tĕsôḇēḇ gāḇer</em>): \"For YHWH has created a new thing on earth: a female will court a man.\" <em>Bārāʾ</em> (to create) is the verb of Genesis 1:1 — a genuinely unprecedented act. The interpretive options for <em>nĕqēḇâ tĕsôḇēḇ gāḇer</em> include: (a) the weakened Israel (female) will now seek YHWH/Messiah (male) in a reversal of the prior rejection; (b) the newly restored nation, whose strength has been restored, will no longer need to be pursued; (c) a proverbial statement about the power-reversal of restoration. Most likely the image follows the preceding \"faithless daughter\" address: instead of the faithless daughter wandering (<em>hitnôdĕdâh</em>, v22a), she turns and pursues — the restoration reverses the direction of wandering. The context of \"something unprecedented\" supports a reading where YHWH's transformative act means the covenant people will be so thoroughly renewed that the typical pattern (people fleeing God) is reversed.</p>",
    "23": "<p><strong>ʾOd yōmĕrû ʾet-haddāḇār hazzeh bĕʾereṣ yĕhûdâ ûḇĕʿārāyw</strong> (<em>ʾOd yōmĕrû</em>): \"they will again say this word in the land of Judah and in its cities\" — the prophetic formula of blessing will be spoken again, implying a restored land, a restored community, and restored liturgical/social speech. <strong>Yĕḇārĕkĕḵā YHWH nĕwēh-ṣedeq har haqōdeš</strong> (<em>nĕwēh-ṣedeq har haqōdeš</em>): \"home of righteousness, O holy mountain\" — the restored Jerusalem's character is defined by <em>ṣedeq</em> (righteousness/justice), which ch31's new covenant will produce by inward transformation. <em>Har haqōdeš</em> (holy mountain) is the Zion theology vocabulary of Pss 2, 48, 87.</p>",
    "24": "<p><strong>Wĕyāšĕḇû ḇâ yĕhûdâ wĕḵol-ʿārāyw yaḥdāw ʾikkārîm wĕnāsĕʿû bĕʿēder</strong> (<em>ʾikkārîm wĕnāsĕʿû bĕʿēder</em>): farmers (<em>ʾikkārîm</em>) and those who move with their flocks (<em>nāsĕʿû bĕʿēder</em>, lit. \"those who journey with the flock\") — the two primary livelihoods of ancient Judah, agricultural and pastoral. Their <em>yaḥdāw</em> (together, united) settlement signals the end of the disruptive migrations and forced removals of war. The normalcy of daily agricultural life is itself a form of restoration.</p>",
    "25": "<p><strong>Kî hirwêtî nefesh ʿăyēpâ wĕḵol-nefesh dāʾăḇâ millēʾtî</strong> (<em>kî hirwêtî nefesh ʿăyēpâ</em>): \"For I have satisfied the weary <em>nefesh</em> and replenished every faint <em>nefesh</em>.\" <em>Nefesh</em> is the whole person — the seat of appetite, longing, vitality. <em>ʿĀyēpâ</em> (weary, exhausted) and <em>dāʾăḇâ</em> (faint, languishing) describe the depleted state of exile; <em>hirwêtî</em> (Hiphil of <em>rāwâ</em>, to drink one's fill, to be saturated) and <em>millēʾtî</em> (I have filled, Piel of <em>māléʾ</em>) are the states of complete satisfaction. This is the experiential basis of the covenant renewal — YHWH first satisfies before commanding.</p>",
    "26": "<p><strong>ʿAl-zōʾt hĕqîṣōtî wāʾerʾeh ûšĕnātî ʿārĕḇâ lî</strong> (<em>ʿAl-zōʾt hĕqîṣōtî wāʾerʾeh ûšĕnātî ʿārĕḇâ lî</em>): \"At this I awoke and looked, and my sleep had been sweet to me.\" A remarkably intimate aside — the prophet awakens from the vision of vv1-25 (<em>hayyôm hazeʾ</em>). The sweetness of the sleep suggests the vision itself was a restorative gift. This brief interruption of the oracular material frames chs 30-31 as a written vision-collection (the \"Book of Consolation\") deliberately set apart from the surrounding material of judgment.</p>",
    "27": "<p><strong>Hinnēh yāmîm bāʾîm</strong> (<em>Hinnēh yāmîm bāʾîm</em>): the eschatological formula marking a new oracle. <strong>Wĕzāraʿtî ʾet-bêt yiśrāʾēl wĕʾet-bêt yĕhûdâ zera ʾādām wĕzera bĕhēmâ</strong> (<em>zera ʾādām wĕzera bĕhēmâ</em>): \"I will sow the house of Israel and the house of Judah with seed of humans and seed of animals\" — the fertility curse of exile (depopulation, livestock death) is reversed with an agricultural image: YHWH as farmer sowing the land with human and animal populations. Both houses together (<em>wĕʾet-bêt yiśrāʾēl wĕʾet-bêt yĕhûdâ</em>) — the unification of north and south continues as a theme.</p>",
    "28": "<p><strong>Wĕhāyâ kaʾăšer šāqadtî ʿălêhem linĕtôš ûlintôṣ ûlĕhaʾărōš ûlĕhaʾăḇîd ûlĕhārēaʿ kēn ʾešqōd ʿălêhem liḇnôt wĕliṭṭôaʿ</strong> (<em>kaʾăšer šāqadtî ʿălêhem linĕtôš</em>): the <em>šāqad</em> wordplay reappears from 1:12 — YHWH \"watches over\" his word to perform it; there he was watching to destroy, now to build. The six infinitives of judgment from 1:10 (<em>linĕtôš ûlintôṣ ûlĕhaʾărōš ûlĕhaʾăḇîd ûlĕhārēaʿ</em>) are now answered with the two infinitives of restoration (<em>liḇnôt wĕliṭṭôaʿ</em>). The book's structural symmetry: what was announced in the inaugural call (1:10) is now being fulfilled in the reverse direction.</p>",
    "29": "<p><strong>Bayyāmîm hāhēm lōʾ-yōmĕrû ʿôd ʾāḇôt ʾāḵĕlû ḇōser ûšinnê ḇānîm tiqhênā</strong> (<em>ʾāḇôt ʾāḵĕlû ḇōser ûšinnê ḇānîm tiqhênā</em>): the sour-grapes proverb also appears in Ezekiel 18:2, where it is similarly rejected. The proverb expresses the complaint of the generation experiencing exile — they are suffering for their ancestors' sins. The rejection of this proverb does not deny intergenerational consequence but announces a new principle of individual accountability in the coming age.</p>",
    "30": "<p><strong>Kî ʾim-ʾîš bĕʿăwōnô yāmût</strong> (<em>kî ʾim-ʾîš bĕʿăwōnô yāmût</em>): \"But each person will die for their own iniquity (<em>ʿāwôn</em>).\" This is the principle of direct accountability that replaces the intergenerational blame-shifting. The phrase <em>kol-hāʾādām hāʾōḵēl habbōser tiqhênā šinnāyw</em> (\"every person who eats sour grapes — their own teeth will be set on edge\") applies the proverb to the individual: the consequence is personal to the one who commits the wrong. This prepares for the new covenant's internalized knowledge (v34) — individual relationship with YHWH means individual accountability.</p>",
    "32": "<p>The contrast clause: <strong>lōʾ kabbĕrît ʾăšer kāratî ʾet-ʾăḇôtām</strong> (<em>lōʾ kabbĕrît ʾăšer kāratî</em>): \"not like the covenant I made with their fathers\" — the new covenant is defined first negatively. <strong>Bĕyôm heḥĕzîqî bĕyādām lĕhôṣîʾām mēʾereṣ miṣrāyim</strong> (<em>bĕyôm heḥĕzîqî bĕyādām</em>): \"on the day I took them by the hand to lead them out of Egypt\" — the intimacy of the exodus relationship, YHWH holding their hand, contrasts sharply with what follows. <strong>ʾăšer-hēmmâ hēpĕrû ʾet-bĕrîtî</strong> (<em>ʾăšer-hēmmâ hēpĕrû</em>): \"a covenant they broke\" — <em>pārar</em> (to break, to annul) is the technical term for covenant violation (cf. Isa 24:5; Ps 55:21). <strong>Wĕʾānōḵî bāʿaltî bām</strong> (<em>wĕʾānōḵî bāʿaltî bām</em>): \"even though I was their husband\" — <em>baʿal</em> as husband/master; the marriage metaphor for the Sinai covenant (cf. Jer 2:2; Hos 2:14-20). The covenant's failure is entirely Israel's — YHWH fulfilled his husband-obligations; they were the unfaithful partner.</p>",
    "33": "<p>The heart of the new covenant: <strong>kî zōʾt habbĕrît ʾăšer ʾeḵrōt ʾet-bêt yiśrāʾēl ʾaḥărê hayyāmîm hāhēm nĕʾum-YHWH nātattî ʾet-tôrātî bĕqirbām wĕʿal-libbām ʾektĕḇennâ</strong>: the covenant is defined by two parallel verbs: <em>nātattî</em> (I will give/put, Qal perfect of <em>nātan</em>) and <em>ʾektĕḇennâ</em> (I will write it, Qal imperfect of <em>kātaḇ</em> with 3fs suffix). <strong>Nātattî ʾet-tôrātî bĕqirbām</strong> (<em>bĕqirbām</em>): \"I will put my <em>tôrâ</em> within them\" — <em>qereb</em> (inward parts, inner being) is the seat of thought and intention. <strong>Wĕʿal-libbām ʾektĕḇennâ</strong> (<em>ʿal-libbām</em>): \"and on their heart I will write it\" — the <em>lēḇ</em>/heart is the organ of will, understanding, and moral disposition in Hebrew anthropology. The contrast with Sinai is absolute: the stone tablets (Exod 24:12; 31:18) are replaced by the heart-tablet. The Torah is not abolished but relocated — from external code to internal disposition. Ezekiel 36:26-27 provides the mechanism: \"I will give you a new heart... I will put my Spirit within you.\" Hebrews 8:8-12 and 10:16 cite Jer 31:33 as the definitive OT anticipation of what Christ accomplishes. <strong>Wĕhāyîtî lāhem lēʾlōhîm wĕhēmmâ yihyû-lî lĕʿām</strong> (<em>wĕhāyîtî lāhem lēʾlōhîm</em>): the covenant formula in its fullest, unconditional form — no \"if\" conditions, no conditional verb.</p>",
    "34": "<p><strong>Wĕlōʾ yĕlammĕdû ʿôd ʾîš ʾet-rēʿēhû wĕʾîš ʾet-ʾāḥîw lēʾmōr dĕʿû ʾet-YHWH</strong> (<em>lēʾmōr dĕʿû ʾet-YHWH</em>): the mediated knowledge of YHWH that characterizes the whole prophetic office — prophets calling Israel to \"know YHWH\" — becomes unnecessary. <strong>Kî-ḵullām yēdĕʿû ʾôtî lĕmiqqĕṭannām wĕʿad-gĕdôlām</strong> (<em>kî-ḵullām yēdĕʿû ʾôtî</em>): \"for they will all know me, from the least to the greatest\" — <em>kol</em> (all) and the universal range (<em>lĕmiqqĕṭannām wĕʿad-gĕdôlām</em>, from the smallest to the greatest) eliminate all exceptions. The <em>yādaʿ</em> here is the relational, covenantal knowing of 1:5 — not merely cognitive. <strong>Kî ʾeslaḥ laʿăwōnām ûlĕḥaṭṭāʾtām lōʾ ʾezkār-ʿôd</strong> (<em>ûlĕḥaṭṭāʾtām lōʾ ʾezkār-ʿôd</em>): \"I will forgive their iniquity and remember their sin no more\" — the double negation (<em>lōʾ... ʿôd</em>, not... again) is absolute. The <em>zākar</em> (remembering) that YHWH exercises in covenant memory is here applied negatively to sin: YHWH will not bring the record of sin back into covenant relationship. Hebrews 10:17 cites this as the definitive proof that the new covenant's sacrifice (Christ's) achieved what the repeated Levitical sacrifices could not — permanent forgiveness.</p>",
    "35": "<p><strong>Kōh ʾāmar YHWH nōtēn šemeš lĕʾôr yômām ḥuqqôt yārēaḥ wĕḵôḵāḇîm lĕʾôr lāylâ</strong> (<em>nōtēn šemeš lĕʾôr yômām</em>): the two cosmic guarantees — sun for daytime light, fixed order of moon and stars for nighttime light — are the standards by which the continuation of Israel's national existence is measured. <em>Ḥuqqôt yārēaḥ wĕḵôḵāḇîm</em> (the fixed orders/decrees of moon and stars) — <em>ḥuqqôt</em> (statutes, fixed orders) transfers the legal covenant vocabulary to the cosmic realm. <strong>Rōgaʿ hayyām wayyehĕmû gallāyw YHWH ṣĕḇāʾôt šĕmô</strong> (<em>rōgaʿ hayyām wayyehĕmû gallāyw</em>): \"who stirs up the sea so that its waves roar\" — the cosmic power language establishes YHWH's authority to make such a guarantee.</p>",
    "36": "<p><strong>ʾIm-yāmûšû haḥuqqîm hāʾēlleh millĕpānay nĕʾum-YHWH gam-zeraʿ yiśrāʾēl yišbĕtû mihyôt-gôy lĕpānay kol-hayyāmîm</strong> (<em>ʾIm-yāmûšû haḥuqqîm hāʾēlleh millĕpānay</em>): the conditional is deliberately impossible — <em>yāmûšû</em> (Qal imperfect of <em>mûš</em>, to depart, to be removed) applied to the cosmic fixed orders. The guarantee of Israel's continuation as a covenant people is as secure as the daily sunrise. <em>Gam-zeraʿ yiśrāʾēl yišbĕtû mihyôt-gôy lĕpānay kol-hayyāmîm</em>: they would cease to be a nation before YHWH only if the cosmos ceased to function — an impossibility. Paul's argument in Rom 11:1-2 (\"Has God rejected his people? By no means!\") stands on exactly this kind of irrevocable promise.</p>",
    "37": "<p><strong>Kōh ʾāmar YHWH ʾim-yimmaddû šāmayim millĕmaʿlâ wĕyēḥāqĕrû môsĕdê-ʾāreṣ lĕmāṭṭâ gam-ʾănî ʾemʾas bĕḵol-zeraʿ yiśrāʾēl</strong> (<em>ʾim-yimmaddû šāmayim millĕmaʿlâ wĕyēḥāqĕrû môsĕdê-ʾāreṣ lĕmāṭṭâ</em>): two impossibilities — the heavens above measured, the foundations of the earth below fully explored. <em>Māʾas</em> (to reject, despise) with <em>bĕḵol-zeraʿ yiśrāʾēl</em> (\"all the offspring of Israel\") — the totality is emphatic: not partial rejection, not conditional rejection, but the total rejection YHWH says cannot happen. <strong>ʿAl kol-ʾăšer ʿāśû</strong> (<em>ʿal kol-ʾăšer ʿāśû</em>): \"for all they have done\" — even accounting for the full record of their sin, rejection is impossible. This is grace that transcends performance.</p>",
    "38": "<p><strong>Hinnēh yāmîm bāʾîm nĕʾum-YHWH wĕniḇnĕtâ hāʿîr lĕ-YHWH mimmigdal Ḥananēʾl ʿad-šaʿar happinnâ</strong> (<em>mimmigdal Ḥananēʾl ʿad-šaʿar happinnâ</em>): the restored city's boundaries are traced beginning at the Tower of Hananeel (NE corner of the city, Neh 3:1; 12:39; Zech 14:10) to the Corner Gate (NW, 2 Kings 14:13). The prophetic topography is precise and geographically verifiable — the promise is rooted in actual Jerusalem geography, not abstracted symbolism.</p>",
    "39": "<p><strong>Wĕyāṣāʾ ʿôd qaw hamiddâ negdô ʿal-gibʿat Gārēḇ ûnāsaḇ Gōʿātâ</strong> (<em>ʿal-gibʿat Gārēḇ ûnāsaḇ Gōʿātâ</em>): the measuring line extends to Gareb Hill and turns toward Goah — locations not certainly identified, but probably in the west and SW of Jerusalem. The expanding perimeter suggests the restored city will be larger than its pre-exile footprint. The detailed boundary description functions as a title deed of promise, as concrete as the field purchase in ch32.</p>",
    "40": "<p><strong>Wĕḵol-hāʿēmeq hapĕgārîm wĕhaddešen wĕḵol-haššĕdēmôt ʿad-naḥal qidrôn ʿad-pinnah šaʿar-hassûsîm mizrāḥâ qōdeš lĕ-YHWH</strong> (<em>Wĕḵol-hāʿēmeq hapĕgārîm wĕhaddešen</em>): the valley of dead bodies (<em>pĕgārîm</em>) and ashes (<em>dešen</em>) — the Hinnom Valley/Tophet, the site of child sacrifice and judgment (7:31-34; 19:6) — will be holy to YHWH. The most defiled space becomes consecrated space. The word <em>qōdeš</em> (holy) applied to what was the valley of slaughter is the ultimate expression of YHWH's restorative power: he does not avoid the defilement, he transforms it. <strong>Lōʾ-yinnātēš wĕlōʾ-yēhārēs ʿôd lĕʿôlām</strong> (<em>lōʾ-yinnātēš wĕlōʾ-yēhārēs ʿôd lĕʿôlām</em>): \"it will never again be uprooted or demolished\" — the six infinitives of judgment from 1:10 are permanently reversed with the two infinitives of building (v28). The city stands forever.</p>"
  },
  "32": {
    "1": "<p><strong>Bišnat hāʿăśirît lĕṣidqiyyāhû melek-yĕhûdâ hî haššānâ šĕmoneh ʿeśrēh šānâ lĕNĕḇuḵadrĕʾṣṣar</strong> (<em>bišnat hāʿăśirît lĕṣidqiyyāhû</em>): the dual dating — 10th year of Zedekiah = 18th year of Nebuchadnezzar — is 588 BCE, a year before Jerusalem falls. The precise dating is significant: this is an acted prophecy of hope performed at the darkest moment. The specificity of dating grounds the sign-act in verifiable historical reality.</p>",
    "2": "<p><strong>Wĕḥêl melek-bāḇel ṣārîm ʿal-yĕrûšālāyim</strong> (<em>wĕḥêl melek-bāḇel ṣārîm ʿal-yĕrûšālāyim</em>): the Babylonian siege (<em>ṣārîm</em>, Qal participle — ongoing action) is the immediate context. <strong>WîrmĕyāhÛ hānnāḇîʾ hāyâ kālûʾ baḥăṣar hammaTTārâ</strong> (<em>kālûʾ baḥăṣar hammaṭṭārâ</em>): Jeremiah is confined (<em>kālûʾ</em>, Qal passive — locked up) in the court of the guard (<em>ḥăṣar hammaṭṭārâ</em>), a semi-open area within the palace complex (Neh 3:25). The imprisonment details sharpen the paradox: a man physically confined performs a sign-act of land-purchase that proclaims freedom and restoration.</p>",
    "3": "<p><strong>ʾĂšer kĕlāʾô ṣidqiyyāhû melek-yĕhûdâ lēʾmōr</strong> (<em>ʾĂšer kĕlāʾô ṣidqiyyāhû</em>): Zedekiah's accusation is reproduced: <em>maddûaʿ ʾattâ nibbāʾ lēʾmōr</em> (\"why do you keep prophesying?\") — the Hitpael of <em>nābāʾ</em> is iterative/habitual action. The content of the prophetic word that earned imprisonment — \"YHWH is handing this city to the king of Babylon\" — is precisely the word being enacted in reverse through the field purchase. Zedekiah opposes the word; Jeremiah enacts hope through the same word.</p>",
    "4": "<p><strong>Wĕṣidqiyyāhû melek-yĕhûdâ lōʾ-yimmāLēṭ miyyad hakkaśdîm</strong> (<em>lōʾ-yimmāLēṭ miyyad hakkaśdîm</em>): the oracle against Zedekiah is stated plainly — no escape. <strong>Kî hinnātēn yinnātēn bĕyad melek bāḇel</strong> (<em>kî hinnātēn yinnātēn</em>): the doubled infinitive absolute makes the surrender absolutely certain: \"he will surely be given.\" <strong>Ûpîw ʾim-pîw yĕdabbēr wĕʿênāyw ʾet-ʿênāyw tirʾênâ</strong> (<em>ûpîw ʾim-pîw yĕdabbēr wĕʿênāyw ʾet-ʿênāyw tirʾênâ</em>): \"his mouth will speak with his mouth and his eyes will see his eyes\" — a personal, face-to-face encounter with Nebuchadnezzar, fulfilling the public humiliation of exile (2 Kings 25:6-7).</p>",
    "5": "<p><strong>Wĕḇāḇel yôliḵ ʾet-ṣidqiyyāhû wĕšām yihyeh ʿad-pŏqĕdî ʾōtô</strong> (<em>ʿad-pŏqĕdî ʾōtô</em>): \"until I attend to him\" — <em>pāqad</em> (to attend to, to visit) is YHWH's sovereign act of intervention, either punitive or restorative. The ambiguity is intentional: Zedekiah will remain in Babylon until YHWH's visitation, whose nature is left open. <strong>Kî tiṣṣĕḇû ʾet-hakkaśdîm lōʾ taṣlîḥû</strong> (<em>kî tiṣṣĕḇû ʾet-hakkaśdîm lōʾ taṣlîḥû</em>): \"if you fight the Chaldeans, you will not succeed\" — military resistance is futile because this is YHWH's judgment, not merely Babylonian aggression.</p>",
    "6": "<p><strong>Wayyōʾmer Yirmĕyāhû hāyâ dĕḇar-YHWH ʾēlay lēʾmōr</strong> (<em>hāyâ dĕḇar-YHWH ʾēlay lēʾmōr</em>): the classic prophetic reception formula introduces the private divine communication that preceded the public sign-act. Jeremiah's narration in the first person (vv6-15) distinguishes this passage from the surrounding third-person biographical prose, lending the account the weight of personal eyewitness testimony.</p>",
    "7": "<p><strong>Hānāmēʾl ben-Šallûm dōdĕḵā bāʾ ʾēlêḵā lēʾmōr qnēh-lĕḵā ʾet-śādĕhî ʾăšer bāʿănātôt kî lĕḵā mišpaṭ haggĕʾullâ liqnôt</strong> (<em>kî lĕḵā mišpaṭ haggĕʾullâ liqnôt</em>): the key legal term: <strong>gĕʾullâ</strong> (<em>gĕʾullâ</em>) — the right of the kinsman-redeemer. Under Leviticus 25:25, when a family member was forced to sell land due to poverty, the nearest kinsman (<em>gōʾēl</em>) had both the right and obligation to purchase it and keep it within the family. Jeremiah as Hanamel's nearest relative has the <em>mišpaṭ haggĕʾullâ</em> (legal right of redemption). The theological weight: YHWH enacts his own <em>gōʾēl</em> role in the restoration (Isa 41:14; 43:1; 44:6), and Jeremiah's act of purchase is the prophetic enactment of that divine redemptive purpose.</p>",
    "8": "<p><strong>Wayyābōʾ ʾēlay Ḥănāmĕʾl ben-dōdî kiddĕḇar YHWH ʾel-ḥăṣar hammaṭṭārâ</strong> (<em>kiddĕḇar YHWH</em>): \"as the word of YHWH had said\" — the prior divine word's exact fulfillment in the cousin's arrival is the confirmation of the divine word's reliability. <strong>Wāʾēdaʿ kî dĕḇar-YHWH hûʾ</strong> (<em>Wāʾēdaʿ kî dĕḇar-YHWH hûʾ</em>): \"I knew that this was the word of YHWH\" — the <em>yādaʿ</em> (to know) is not mere recognition but the relational, experiential certitude that this purchase is YHWH's commanded act. Faith is enacted through a legal transaction in the face of imminent catastrophe.</p>",
    "9": "<p><strong>Wāʾeqneh ʾet-haśśādeh mēʾēt Ḥănāmĕʾl ben-dōdî ʾăšer bāʿănātôt</strong> (<em>Wāʾeqneh ʾet-haśśādeh</em>): the actual purchase. <strong>Wāʾeškōl-lô ʾet-hakkesep šiḇʿâ šeqālîm waʿăśārâ hakkesep</strong> (<em>šiḇʿâ šeqālîm waʿăśārâ hakkesep</em>): seventeen shekels of silver. The specific price (<em>wāʾeškōl-lô</em>, I weighed out to him) is verifiable detail — this is not symbolic; it is a legal transaction conducted with precision. Anathoth is already captured by the Babylonians; the purchase has no immediate commercial value. Its entire value is eschatological: it enacts trust in YHWH's future.</p>",
    "10": "<p><strong>Wāʾeḵtōḇ bassēper wāʾeḥtōm wāʾāʿēd ʿēdîm wāʾeškōl hakkesep bĕmōznāyim</strong> (<em>Wāʾeḵtōḇ bassēper wāʾeḥtōm wāʾāʿēd ʿēdîm</em>): four verbs of legal procedure — I wrote (<em>kātaḇ</em>), I sealed (<em>ḥātam</em>), I brought in witnesses (<em>ʿûd</em> Hiphil), I weighed (<em>šāqal</em>). Each verb represents a standard step in ancient Near Eastern property law. The Babylonian and Assyrian parallel purchase documents confirm that this description is technically accurate to the period. The prophetic act is simultaneously a genuine legal transaction and a theological statement.</p>",
    "11": "<p><strong>Wāʾeqqaḥ ʾet-sēper hammiqqnâ ʾet-hehātûm hammîṣwâ wĕhaḥuqqîm wĕʾet-haggālûy</strong> (<em>ʾet-hehātûm hammîṣwâ wĕhaḥuqqîm wĕʾet-haggālûy</em>): the purchase document came in two copies — a sealed copy containing the full terms and conditions (<em>hammiṣwâ wĕhaḥuqqîm</em>) and an open copy. This matches the standard ANE practice of a duplicate deed with one sealed for long-term preservation and one open for immediate reference. The sealed copy was the legally binding original; the open copy the working document.</p>",
    "12": "<p><strong>Wāʾettēn ʾet-sēper hammiqqnâ ʾel-Bārûḵ ben-Nēriyyâ ben-Maḥsēyâ</strong> (<em>ʾel-Bārûḵ ben-Nēriyyâ ben-Maḥsēyâ</em>): Baruch the scribe — Jeremiah's closest associate, the one who wrote the scroll in ch36 — receives the deed in the presence of Hanamel, the witnesses, and all the Judeans in the court of the guard. The public nature of the transaction before multiple witnesses invests it with maximum legal force. Baruch's role as custodian of the documents connects the sign-act to the prophetic literary legacy.</p>",
    "13": "<p><strong>Wāʾăṣawweh ʾet-Bārûḵ lĕʿênêhem lēʾmōr</strong> (<em>Wāʾăṣawweh ʾet-Bārûḵ lĕʿênêhem</em>): the formal instruction (<em>ṣāwâ</em>) given to Baruch publicly (\"before their eyes\") — this is not a private arrangement but a public prophetic declaration enacted through legal form. The oral instructions give the legal transaction its interpretive framework.</p>",
    "14": "<p><strong>Kōh-ʾāmar YHWH ṣĕḇāʾôt ʾĕlōhê yiśrāʾēl qāḥ ʾet-hassĕpārîm hāʾēlleh ʾēt sēper hammiqqnâ hazzeh wĕʾēt hehātûm wĕʾēt sēper haggālûy hazzeh wĕnĕtattām biḵlî-ḥāreś lĕmaʿan yaʿamĕdû yāmîm rabbîm</strong> (<em>biḵlî-ḥāreś lĕmaʿan yaʿamĕdû yāmîm rabbîm</em>): the clay jar (<em>kĕlî ḥāreś</em>) for long-term preservation — the same technology that preserved the Dead Sea Scrolls for two millennia. The purpose: <em>lĕmaʿan yaʿamĕdû yāmîm rabbîm</em> (\"that they may stand for many days\"). The documents are not just legal evidence for an immediate transaction; they are a long-term prophetic charter meant to outlast the current catastrophe.</p>",
    "15": "<p><strong>Kî ḵōh ʾāmar YHWH ṣĕḇāʾôt ʾĕlōhê yiśrāʾēl ʿôd yiqqānû ḇāttîm ûśādôt ûḵĕrāmîm bāʾāreṣ hazzōʾt</strong> (<em>ʿôd yiqqānû ḇāttîm ûśādôt ûḵĕrāmîm bāʾāreṣ hazzōʾt</em>): \"houses and fields and vineyards will yet be bought in this land.\" The word that interprets the sign-act: the purchase is not an individual eccentricity but a divinely-ordered prophetic enactment of the future. The three categories — houses (<em>bāttîm</em>), fields (<em>śādôt</em>), vineyards (<em>ḵĕrāmîm</em>) — represent the full range of productive property. The prophecy anticipates not just land ownership but a functioning agricultural economy.</p>",
    "16": "<p><strong>Wāʾetpallēl ʾel-YHWH ʾaḥărê titî ʾet-sēper hammiqqnâ ʾel-Bārûḵ ben-Nēriyyâ lēʾmōr</strong> (<em>Wāʾetpallēl ʾel-YHWH ʾaḥărê</em>): the prayer follows the sign-act. The sequence is significant: Jeremiah first obeys the command to purchase (<em>then</em> prays), which is the pattern of faith-obedience preceding understanding. The Hitpael of <em>pālal</em> (to pray, intercede) is the same form used in 7:16 when YHWH forbade intercession — the prohibition has been lifted by the new reality of the sign-act of restoration.</p>",
    "17": "<p><strong>ʾĂhāh ʾădōnāy YHWH</strong> (<em>ʾĂhāh ʾădōnāy YHWH</em>): the unique prayer opening — <em>ʾăhāh</em> (Ah!/Alas!) combined with <em>ʾădōnāy YHWH</em> (Lord GOD) expresses a kind of reverent astonishment. It appears also in 1:6 (Jeremiah's initial objection to his call), 4:10, and 14:13 — always as a cry from the depth of bewilderment before the paradox of divine action. <strong>Hinnēh ʾattâ ʿāśîtā ʾet-haššāmayim wĕʾet-hāʾāreṣ bĕḵōḥăḵā haggādôl ûbiḏrōʿăḵā haNNĕṭûyâ lōʾ-yippālēʾ mimmĕḵā kol-dāḇār</strong> (<em>lōʾ-yippālēʾ mimmĕḵā kol-dāḇār</em>): the creation formula grounds YHWH's power — heaven and earth made by the great power (<em>kōaḥ gādôl</em>) and outstretched arm (<em>zĕrôaʿ nĕṭûyâ</em>). The <em>lōʾ-yippālēʾ mimmĕḵā kol-dāḇār</em> (\"nothing is too difficult/wonderful for you\") is the Niphal of <em>pālāʾ</em> (to be wonderful, beyond normal human capacity) — what is <em>pālāʾ</em> for humans is not so for YHWH. The prayer's answer in v27 echoes this exactly.</p>",
    "18": "<p><strong>ʿŌśeh ḥesed lāʾălāpîm ûmĕšallēm ʿăwōn ʾāḇôt ʾel-ḥêq bĕnêhem ʾaḥărêhem</strong> (<em>ûmĕšallēm ʿăwōn ʾāḇôt ʾel-ḥêq bĕnêhem</em>): the tension of <em>ḥesed</em> (steadfast love) extended to thousands (<em>lāʾălāpîm</em>, cf. Exod 20:6) alongside punishment (<em>šillēm</em>, Piel of <em>šālam</em>, to repay, make whole) of ancestral iniquity into the laps of descendants. This is the Sinai tension of Exod 34:6-7, cited in Jeremiah's prayer as the theological framework of the crisis — how can the God of <em>ḥesed</em> punish at all, and how can the God of justice extend mercy? The new covenant of ch31 resolves this tension: the forgiveness is complete and the ancestral debt is cancelled.</p>",
    "19": "<p><strong>Gĕdōl hāʿēṣâ wĕrab hāʿălîliyyâ ʾăšer-ʿênêḵā pĕqūḥôt ʿal-kol-darkê bĕnê-ʾādām lātēt lĕʾîš kiddĕrāḵāyw ûḵipĕrî maʿălālay</strong> (<em>ʾăšer-ʿênêḵā pĕqūḥôt ʿal-kol-darkê bĕnê-ʾādām</em>): YHWH's eyes are open to all the ways of human beings — omniscience as moral oversight. The divine council theology of Job 1-2, Ps 139, Zech 4:10 (seven eyes that range through the whole earth) underlies this. <strong>Lātēt lĕʾîš kiddĕrāḵāyw ûḵipĕrî maʿălālay</strong> (<em>lātēt lĕʾîš kiddĕrāḵāyw</em>): retributive justice is not mechanical fate but YHWH's personal, morally attentive response to each person's deeds.</p>",
    "20": "<p><strong>ʾĂšer-śamtā ʾōtôt ûmôpĕtîm bĕʾereṣ miṣrāyim wĕʿad-hayyôm hazzeh ûḇĕyiśrāʾēl ûḇāʾādām</strong> (<em>ʾōtôt ûmôpĕtîm bĕʾereṣ miṣrāyim</em>): the exodus signs and wonders (<em>ʾōtôt ûmôpĕtîm</em>) — the Deuteronomic language of the ten plagues and the sea-crossing — are cited as evidence of YHWH's historical fidelity. <strong>Wattaʿăśeh-lĕḵā šēm kĕhayyôm hazzeh</strong> (<em>Wattaʿăśeh-lĕḵā šēm kĕhayyôm hazzeh</em>): the exodus created YHWH's <em>šēm</em> (name, reputation) — a demonstration of divine character that endures to Jeremiah's present. The prayer positions the current crisis as requiring an equally definitive act of YHWH-revelation.</p>",
    "21": "<p><strong>Wattôṣēʾ ʾet-ʿammĕḵā ʾet-yiśrāʾēl mēʾereṣ miṣrāyim bĕʾōtôt ûḇĕmôpĕtîm ûḇĕyād ḥăzāqâ ûḇiḏrôaʿ nĕṭûyâ ûḇĕmôrāʾ gādôl</strong> (<em>bĕyād ḥăzāqâ ûḇiḏrôaʿ nĕṭûyâ</em>): the tricolon of exodus power — mighty hand, outstretched arm, great terror — is the Deuteronomic formula (Deut 4:34; 5:15; 7:19; 11:2; 26:8) that defines YHWH's saving intervention. The prayer's historical rehearsal is not mere recitation but the activation of covenant memory: YHWH who acted thus for Israel in Egypt is the same YHWH being addressed now.</p>",
    "22": "<p><strong>Wattittēn lāhem ʾet-hāʾāreṣ hazzōʾt ʾăšer nišbaʿtā lăʾăḇôtām lātēt lāhem ʾereṣ zāḇat ḥālāḇ ûdĕḇāš</strong> (<em>ʾereṣ zāḇat ḥālāḇ ûdĕḇāš</em>): the land flowing with milk and honey — the covenant promise to the patriarchs (Exod 3:8, 17; 13:5; 33:3; Lev 20:24; Num 13:27; Deut 6:3 etc.) — was given; Israel entered and took possession. The prayer establishes the full arc of covenant history: promise → exodus → settlement → failure → judgment. This arc creates the context within which the restoration promise of ch31 is the climactic reversal.</p>",
    "23": "<p><strong>Wayyāḇōʾû wayyirĕšû ʾōtāh wĕlōʾ šāmĕʿû bĕqôlĕḵā ûḇĕtôrātĕḵā lōʾ-hālāḵû ʾēt kol-ʾăšer-ṣiwwîtā ʾôtām laʿăśôt lōʾ ʿāśû</strong> (<em>wĕlōʾ šāmĕʿû bĕqôlĕḵā ûḇĕtôrātĕḵā lōʾ-hālāḵû</em>): the three-fold negation — did not listen to your voice, did not walk in your Torah, did not do all you commanded — summarizes the entire pre-exile history. <strong>Wattaḇiʾ ʾălêhem ʾēt kol-hārāʿâ hazzōʾt</strong> (<em>Wattaḇiʾ ʾălêhem ʾēt kol-hārāʿâ hazzōʾt</em>): \"Therefore you brought all this disaster on them\" — the prayer's theology of history is unambiguous: the exile is YHWH's just response to covenant infidelity. Jeremiah does not pray for YHWH to change his assessment; he prays in the context of complete agreement with YHWH's judgment.</p>",
    "24": "<p><strong>Hinnēh hasōlĕlôt bāʾû hāʿîr lĕlŏkdāh</strong> (<em>Hinnēh hasōlĕlôt bāʾû hāʿîr</em>): the siege ramps (<em>sōlĕlôt</em>) are a visible, physical confirmation of the prophetic word — the disaster YHWH announced has arrived. <strong>Wĕhāʿîr nittĕnâ bĕyad hakkaśdîm hammiLlāḥămîm ʿālêhā</strong> (<em>Wĕhāʿîr nittĕnâ bĕyad hakkaśdîm</em>): the city is being given (<em>nittĕnâ</em>, Niphal perfect — prophetic perfect of certainty) into the hand of the Chaldeans. <strong>ʾĂšer dibbartā hāyâ wĕhinnĕḵā rōʾeh</strong> (<em>ʾĂšer dibbartā hāyâ wĕhinnĕḵā rōʾeh</em>): \"What you said has come true, and you yourself see it\" — the prayer acknowledges the full evidence of judgment before making its final appeal.</p>",
    "25": "<p><strong>Wĕʾattâ ʾădōnāy YHWH ʾāmartā ʾēlay qnēh-lĕḵā haśśādeh bakkesep wĕhāʿēd ʿēdîm wĕhāʿîr nittĕnâ bĕyad hakkaśdîm</strong> (<em>Wĕʾattâ ʾădōnāy YHWH ʾāmartā ʾēlay qnēh-lĕḵā haśśādeh bakkesep</em>): the prayer's climactic paradox: \"You have told me: Buy the field with money and get witnesses — even though the city is being handed to the Chaldeans.\" This is the prayer of a man caught between two divine words — the word of judgment being enacted outside his window and the word of restoration being enacted through his legal transaction. The prayer does not resolve the paradox; it simply presents it to YHWH, confident that YHWH's answer will be the reconciliation of both words. The faith of vv7-15 was enacted in action; now it is expressed in prayer.</p>",
    "26": "<p><strong>Wayhî dĕḇar-YHWH ʾel-Yirmĕyāhû lēʾmōr</strong> (<em>Wayhî dĕḇar-YHWH ʾel-Yirmĕyāhû lēʾmōr</em>): the divine response comes immediately after the prayer, introduced by the standard prophetic reception formula. The answer occupies the rest of the chapter (vv27-44). The structure — human obedience → prayer → divine word — models prophetic intercession as the movement through which YHWH chooses to explain his redemptive purposes.</p>",
    "27": "<p><strong>Hinnēh ʾănî YHWH ʾĕlōhê kol-bāśār hăyippālēʾ mimmennî kol-dāḇār</strong> (<em>ʾănî YHWH ʾĕlōhê kol-bāśār hăyippālēʾ mimmennî kol-dāḇār</em>): YHWH's self-identification: \"I am the LORD, the God of all flesh\" — <em>kol-bāśār</em> (all flesh) transcends Israel; this is universal sovereignty. The rhetorical question echoes Jeremiah's prayer (v17: <em>lōʾ-yippālēʾ mimmĕḵā kol-dāḇār</em>) and returns it as divine declaration: \"Is anything too difficult (<em>yippālēʾ</em>) for me?\" The answer to the paradox of v25 is the transcendent power of YHWH over all flesh and all circumstances. Luke 1:37 (\"For nothing will be impossible with God\") applies the same <em>adynaton</em> formula to the annunciation.</p>",
    "28": "<p><strong>Lāḵēn kōh ʾāmar YHWH hinnĕnî nōtēn ʾet-hāʿîr hazzōʾt bĕyad hakkaśdîm</strong> (<em>hinnĕnî nōtēn ʾet-hāʿîr hazzōʾt bĕyad hakkaśdîm</em>): the divine word confirms the judgment unambiguously — the <em>hinnēnî</em> (\"behold me\") emphasizes YHWH's personal agency in the handing-over. The restoration promise does not cancel or mitigate the judgment; it follows it. Both words stand: the city will fall (vv28-35) and houses and fields will yet be bought (v15; vv36-44).</p>",
    "29": "<p><strong>Ûḇāʾû hakkaśdîm hammiLlāḥămîm ʿal-hāʿîr hazzōʾt wĕhiṣṣîtû ʾet-hāʿîr hazzōʾt bāʾēš ûśĕrāpûhā</strong> (<em>wĕhiṣṣîtû ʾet-hāʿîr hazzōʾt bāʾēš</em>): the burning of the city is stated plainly. <strong>Wĕʾet-habbāttîm ʾăšer qiṭṭĕrû ʿal-gaggôtêhem laBBaʿal wĕhissĕkû nĕsāḵîm lēʾlōhîm ʾăḥērîm lĕmaʿan hakʿisēnî</strong> (<em>lĕmaʿan hakʿisēnî</em>): \"to provoke me to anger\" — the rooftop incense and drink offerings to Baal and other gods are explicitly cited as the cause of judgment. The covenant lawsuit (7:31; 19:5 on Molech; 44:17 on the queen of heaven) is the theological basis of the military catastrophe.</p>",
    "30": "<p><strong>Kî-hāyû bĕnê yiśrāʾēl ûḇĕnê yĕhûdâ raq ʿōśîm hārāʿ bĕʿênay minnĕʿurêhem</strong> (<em>raq ʿōśîm hārāʿ bĕʿênay minnĕʿurêhem</em>): \"only doing evil in my eyes from their youth\" — the indictment is temporal (<em>minnĕʿurêhem</em>, \"from their youth\") and total (<em>raq ʿōśîm</em>, \"doing nothing but evil\"). This parallels the earlier accusation against Jerusalem in 2:20-22 (\"from of old I broke your yoke\") and recalls YHWH's repeated sending of prophets (7:25; 11:7; 25:3-4; 26:5; 29:19; 35:15; 44:4). The long history of repeated sending and repeated rejection is the weight behind the judgment.</p>",
    "31": "<p><strong>Kî ʿal-ʾapî wĕʿal-ḥămātî hāytâ lî hāʿîr hazzōʾt lĕminnê hayyôm ʾăšer bānû ʾôtāh wĕʿad hayyôm hazzeh</strong> (<em>lĕminnê hayyôm ʾăšer bānû ʾôtāh wĕʿad hayyôm hazzeh</em>): \"from the day it was built to this day\" — the scope of provocation is the entire history of Jerusalem from its establishment as David's capital. The city's founding did not change the fundamental disposition of its inhabitants. The oracle anticipates the critique in Acts 7:51 (Stephen's speech): the stiff-necked people \"always resist the Holy Spirit,\" from Moses to Jesus.</p>",
    "32": "<p><strong>ʿAl kol-rāʿat bĕnê yiśrāʾēl ûḇĕnê yĕhûdâ ʾăšer ʿāśû lĕhaḵʿisēnî hēmmâ malkêhem śārêhem kōhănêhem ûnĕḇiʾêhem wĕʾîš yĕhûdâ wĕyōšĕḇê yĕrûšālāyim</strong>: the comprehensive list of offenders — kings, officials, priests, prophets, the men of Judah, and the residents of Jerusalem. No class, no office, no tier of society is exempted. The total coverage is significant for the new covenant promise of ch31:34 (\"they will all know me, from the least to the greatest\") — the new covenant must be as comprehensive as the indictment.</p>",
    "33": "<p><strong>Wayyipnû ʾēlay ʿōrep wĕlōʾ pānîm</strong> (<em>Wayyipnû ʾēlay ʿōrep wĕlōʾ pānîm</em>): \"they turned their backs (<em>ʿōrep</em>) to me, not their faces (<em>pānîm</em>)\" — the spatial metaphor for apostasy: to turn the neck/back is to reject relationship; to turn the face is to enter it. Ezekiel uses the same imagery (Ezek 8:16: worshipers \"turning their backs to the temple of the LORD and facing east\"). <strong>Wĕlammēd ʾôtām haškēm wĕlammēd wĕʾênām šōmĕʿîm lāqaḥat mûsār</strong> (<em>haškēm wĕlammēd</em>): \"rising early to teach\" — the <em>haškēm</em> (rising early) formula used throughout Jeremiah for urgent, persistent prophetic address (7:13; 7:25; 11:7; 25:3-4) is now applied to divine teaching: YHWH himself persistently taught, and they persistently refused correction (<em>mûsār</em>).</p>",
    "34": "<p><strong>Wayyāśîmû šiqqûṣêhem babbayit ʾăšer niqrāʾ-šĕmî ʿālāyw lĕṭammĕʾô</strong> (<em>šiqqûṣêhem babbayit ʾăšer niqrāʾ-šĕmî ʿālāyw</em>): detestable things (<em>šiqqûṣîm</em> — the technical term for idols, Deut 7:26; 29:17; Ezek 5:11) in the temple that bears YHWH's name. The profanation of the name (<em>niqrāʾ-šĕmî ʿālāyw</em>) is the precise violation of the Decalogue's third commandment (Exod 20:7: \"you shall not take the name of the LORD your God in vain\") applied institutionally. The temple, intended to be the house of YHWH's name, became the house of his rivals.</p>",
    "35": "<p><strong>Wayyiḇnû ʾet-bāmôt habbaʿal ʾăšer bĕgêʾ ḇen-Hinnōm lĕhaʿăḇîr ʾet-bĕnêhem wĕʾet-bĕnôtêhem lammōleḵ ʾăšer lōʾ-ṣiwwîtîm wĕlōʾ ʿālĕtâ ʿal-libbî</strong>: the triple negation for Molech child sacrifice — <em>lōʾ-ṣiwwîtîm</em> (I did not command them), <em>wĕlōʾ ʿālĕtâ ʿal-libbî</em> (it did not come up on my heart/mind) — matches 7:31 and 19:5 exactly. The repetition in three separate contexts (7, 19, 32) functions as legal triple attestation: YHWH's total disavowal of the practice is absolute and documented. The phrase <em>lōʾ ʿālĕtâ ʿal-libbî</em> (it never entered my mind) is an extreme statement — the very thought was alien to YHWH's nature.</p>",
    "36": "<p><strong>Wĕʿattâ lāḵēn kōh-ʾāmar YHWH ʾĕlōhê yiśrāʾēl ʾel-hāʿîr hazzōʾt ʾăšer ʾattem ʾōmĕrîm nittĕnâ bĕyad melek bāḇel bĕḥereḇ ûḇārāʿāḇ ûḇaddāḇer</strong> (<em>Wĕʿattâ lāḵēn</em>): the transitional <em>wĕʿattâ lāḵēn</em> (\"now therefore\") pivots from indictment (vv28-35) to restoration promise (vv36-44). The city being delivered by sword, famine, and plague is the acknowledged reality; what follows is not a denial of it but YHWH's word about what comes after.</p>",
    "37": "<p><strong>Hinnĕnî mĕqabbĕṣām mikkol-hāʾărāṣôt ʾăšer hiddaḥtîm šām bĕʾappî ûḇăḥămātî ûḇĕqeṣep gādôl</strong> (<em>mikkol-hāʾărāṣôt ʾăšer hiddaḥtîm šām</em>): the gathering from all the lands is YHWH's direct reversal of the scattering. <em>bĕʾappî ûḇăḥămātî ûḇĕqeṣep gādôl</em> (in my anger, fury, and great wrath) — the same three terms used in ch30's opening oracle — acknowledges that the scattering was genuine divine anger, not merely Babylonian military superiority. <strong>Wahăšîḇōtîm ʾel-hammāqôm hazzeh wĕhôšaḇtîm lāḇeṭaḥ</strong> (<em>wĕhôšaḇtîm lāḇeṭaḥ</em>): the security (<em>beṭaḥ</em>) of the restored community is YHWH's guarantee, not their own military capacity.</p>",
    "38": "<p><strong>Wĕhāyû-lî lĕʿām wăʾănî ʾehyeh lāhem lēʾlōhîm</strong> (<em>Wĕhāyû-lî lĕʿām wăʾănî ʾehyeh lāhem lēʾlōhîm</em>): the covenant formula in its restored form. The formula appears in both the Sinai covenant (Lev 26:12; Exod 6:7) and the new covenant (Jer 31:33; Ezek 36:28; 37:27; Rev 21:3). The simplicity of the declaration — \"they will be my people, and I will be their God\" — contains all covenant theology. In 32:38 it is restoration of what was broken; in 31:33 it is the new covenant's fulfillment; in Rev 21:3 it is the eschatological completion of the entire biblical trajectory.</p>",
    "39": "<p><strong>Wĕnātattî lāhem lēḇ ʾeḥād wĕdereḵ ʾeḥād lĕyirʾâ ʾôtî kol-hayyāmîm lĕṭôḇ lāhem wĕliḇnêhem ʾaḥărêhem</strong> (<em>lēḇ ʾeḥād wĕdereḵ ʾeḥād</em>): \"one heart and one way\" — the <em>lēḇ ʾeḥād</em> (one heart) is the community-level version of the new covenant's internal Torah (31:33). Ezekiel 11:19-20 and 36:26 give the mechanism: removal of the heart of stone, implantation of a heart of flesh with the Spirit. <em>lĕyirʾâ ʾôtî kol-hayyāmîm</em> (to fear me all the days) — the <em>yirʾat YHWH</em> (fear of YHWH) is not an emotion to be cultivated but a divine gift to be given: YHWH will put his fear in their hearts (v40).</p>",
    "40": "<p><strong>Wĕkāratî lāhem bĕrît ʿôlām ʾăšer lōʾ-ʾāšûḇ mēʾaḥărêhem lĕhêṭîḇ ʾôtām wĕʾet-yirʾātî ʾettēn bĕlibbām lĕḇiltî sûr mēʿālay</strong>: the everlasting covenant (<em>bĕrît ʿôlām</em>) contains the resolution of the covenant problem — YHWH guarantees his own fidelity (<em>lōʾ-ʾāšûḇ mēʾaḥărêhem</em>, \"I will never turn away from doing good to them\") and the people's fidelity (<em>wĕʾet-yirʾātî ʾettēn bĕlibbām lĕḇiltî sûr mēʿālay</em>, \"I will put my fear in their hearts so they will not turn away from me\"). The failure of the Sinai covenant was Israel's unfaithfulness; the new everlasting covenant removes the structural cause of that failure by making human faithfulness a divine provision, not a human achievement. Hebrews 13:20-21 cites this \"eternal covenant\" as the ground of the divine work in believers.</p>",
    "41": "<p><strong>Wĕśaśtî ʿălêhem lĕhêṭîḇ ʾôtām wĕnāṭaʿtîm bāʾāreṣ hazzōʾt bĕʾemet bĕḵol-libbî ûḇĕḵol-napšî</strong> (<em>Wĕśaśtî ʿălêhem lĕhêṭîḇ ʾôtām</em>): \"I will rejoice in doing good to them\" — <em>śûś</em> (to rejoice, exult) is divine delight in the act of blessing. <strong>bĕḵol-libbî ûḇĕḵol-napšî</strong> (<em>bĕḵol-libbî ûḇĕḵol-napšî</em>): \"with all my heart and all my soul\" — YHWH applies the Shema language to himself (Deut 6:5: \"love YHWH your God with all your heart and all your soul\"). The command Israel failed to obey, YHWH fulfills toward them: his covenant commitment is a whole-hearted, whole-being investment in their good. Zephaniah 3:17 echoes this: \"He will rejoice over you with gladness; he will quiet you by his love; he will exult over you with loud singing.\"</p>",
    "42": "<p><strong>Kî ḵōh ʾāmar YHWH kaʾăšer hēḇēʾtî ʾel-hāʿām hazzeh ʾēt kol-hārāʿâ haggĕdōlâ hazzōʾt kēn ʾānōḵî mēḇîʾ ʾălêhem ʾet kol-haṭṭôḇâ ʾăšer ʾānōḵî dōḇēr ʾălêhem</strong> (<em>kaʾăšer hēḇēʾtî... kēn ʾānōḵî mēḇîʾ</em>): \"Just as I have brought all this great disaster... so I will bring on them all the good.\" The <em>kāʾăšer... kēn</em> (as... so) structure uses the certainty of the judgment-fulfillment as the guarantee of the restoration-fulfillment. If the word of judgment was reliable (and v24 confirms it is being enacted), the word of restoration is equally reliable. The same sovereignty that brought the disaster brings the good.</p>",
    "43": "<p><strong>Wĕniknû haśśādôt bāʾāreṣ hazzōʾt ʾăšer ʾattem ʾōmĕrîm šĕmāmâ hî mēʾên ʾādām ûḇĕhēmâ nittĕnâ bĕyad hakkaśdîm</strong> (<em>ʾăšer ʾattem ʾōmĕrîm šĕmāmâ hî mēʾên ʾādām ûḇĕhēmâ</em>): \"the land about which you say it is desolate, without man or beast.\" The human perception of total desolation (siege, fall, deportation) is acknowledged as the present reality. <strong>Wĕniknû haśśādôt bāʾāreṣ hazzōʾt</strong> (<em>Wĕniknû haśśādôt bāʾāreṣ hazzōʾt</em>): \"Fields will be bought in this land\" — the prophecy of vv9-15 is now declared as YHWH's own word: the field purchase is the enacted sign of what YHWH has determined to do.</p>",
    "44": "<p><strong>Śādôt bakkesep yiqnû wĕkātôḇ bassēper wĕḥātôm wĕhāʿēd ʿēdîm bĕʾereṣ Binyāmîn ûḇisĕḇîḇôt yĕrûšālāyim ûḇĕʿārê yĕhûdâ ûḇĕʿārê hāhār ûḇĕʿārê haššĕpēlâ ûḇĕʿārê hannegeḇ kî ʾāšîḇ ʾet-šĕḇûtām nĕʾum-YHWH</strong>: the final verse encompasses the full geographical range of the land of Israel — Benjamin (Jeremiah's own tribe, where Anathoth is), the environs of Jerusalem, the towns of Judah, the hill country (<em>hāhār</em>), the Shephelah (<em>haššĕpēlâ</em>), and the Negev. The comprehensive geography is the scope of the promise: the entire land will be restored. The chapter closes with the covenantal formula <em>kî ʾāšîḇ ʾet-šĕḇûtām</em> (\"for I will restore their fortunes\") — a technical term (<em>šûḇ šĕḇût/šĕḇît</em>) used repeatedly in restoration oracles (30:3, 18; 31:23; 33:7, 11, 26; Job 42:10; Ezek 16:53; Amos 9:14; Zeph 3:20) for the comprehensive reversal of exile. The field purchase of vv7-15 is thus the sign of what v44 declares as YHWH's absolute promise.</p>"
  }
}

def main():
    existing = load_comm("original", "jeremiah")
    merge_comm(existing, JEREMIAH)
    save_comm("original", "jeremiah", existing)
    total = sum(len(v) for v in existing.values())
    print(f"Jeremiah mkt-original: {len(existing)} chapters, {total} verses total.")

if __name__ == "__main__":
    main()
